import{_ as t,M as i,p,q as o,R as n,t as s,N as l,a1 as e}from"./framework-5866ffd3.js";const c={},r=e(`<h2 id="简介" tabindex="-1"><a class="header-anchor" href="#简介" aria-hidden="true">#</a> 简介</h2><p>Code-server是一个基于浏览器的开源项目，它将Visual Studio Code (VS Code)的开发环境以Web应用的形式提供。它允许您通过浏览器远程访问和使用VS Code的完整功能，无论您在何处，只要有网络连接，就可以使用自己喜欢的编辑器进行编码和开发。</p><p>下面是Code-server的一些主要特点和功能：</p><ul><li><p><strong>远程开发环境</strong>：Code-server提供了一个完整的VS Code开发环境，包括语法高亮、代码补全、调试、版本控制等功能。您可以使用任何支持现代浏览器的设备访问Code-server，例如个人电脑、笔记本电脑、平板电脑等。</p></li><li><p>跨平台支持：Code-server可以运行在各种操作系统上，包括Windows、macOS和Linux。这使得您可以在不同的设备和操作系统上保持一致的开发环境。</p></li><li><p><strong>可定制性</strong>：Code-server支持大部分VS Code的扩展和插件，您可以根据需要安装和配置您喜欢的扩展，以满足特定的开发需求。它还提供了一些自定义选项，可以根据个人偏好进行界面和行为的调整。</p></li><li><p><strong>协作和共享</strong>：通过Code-server，您可以与他人协作开发，共享代码和项目。您可以与团队成员同时编辑和预览代码，通过浏览器实时交流和协作。</p></li><li><p><strong>安全性</strong>：Code-server提供了一些安全措施，包括访问控制和身份验证。您可以通过设置密码、使用SSL等方式来保护Code-server的访问和数据传输安全。</p></li><li><p><strong>灵活的部署方式</strong>：Code-server可以以自托管方式部署在您自己的服务器或本地环境中。您可以根据需要自定义部署方式，并根据实际需求进行扩展和配置。</p></li></ul><p>Code-server为开发者提供了一种方便、灵活和跨平台的远程开发环境。无论是个人开发者还是团队协作，Code-server都可以提供一种无缝的开发体验，让您在任何地方都能获得高效的开发工具和环境。</p><p>文档：https://coder.com/docs/code-server/latest<br> Github: https://github.com/coder/code-server</p><h2 id="安装" tabindex="-1"><a class="header-anchor" href="#安装" aria-hidden="true">#</a> 安装</h2><ul><li>一键脚本安装：</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">curl</span> <span class="token parameter variable">-fsSL</span> https://code-server.dev/install.sh <span class="token operator">|</span> <span class="token function">sh</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>安装完成后，启动。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 1. 现在启动并加入开机自启</span>
<span class="token function">sudo</span> systemctl <span class="token builtin class-name">enable</span> <span class="token parameter variable">--now</span> code-server@<span class="token environment constant">$USER</span>

<span class="token comment"># 查看运行状态</span>
<span class="token function">sudo</span> systemctl status code-server@<span class="token environment constant">$USER</span>

<span class="token comment"># 2. 前台启动</span>
code-server

<span class="token comment"># 3. 指定端口启动</span>
<span class="token assign-left variable">PORT</span><span class="token operator">=</span><span class="token number">8072</span> code-server

<span class="token comment"># or</span>
code-server --bind-addr <span class="token number">127.0</span>.0.1:8072
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>默认脚本会在8080端口提供服务，打开网页可以看到如下界面：</p><p><img src="https://minio.kevin2li.top/image-bed/blog/20230521152655.png" alt=""></p><p>密码可在<code>~/.config/code-server/config.yaml</code>中查看。</p><p>登录成功后即可看到熟悉的vscode界面。</p><p><img src="https://minio.kevin2li.top/image-bed/blog/20230521152903.png" alt=""></p><h2 id="使用" tabindex="-1"><a class="header-anchor" href="#使用" aria-hidden="true">#</a> 使用</h2><h3 id="导入profile" tabindex="-1"><a class="header-anchor" href="#导入profile" aria-hidden="true">#</a> 导入profile</h3><p>为了保持开发环境的一致性，可以将自己之前常用的配置直接导入到云开发环境中。</p><p><img src="https://minio.kevin2li.top/image-bed/blog/20230521164607.png" alt=""></p><h3 id="暴露服务" tabindex="-1"><a class="header-anchor" href="#暴露服务" aria-hidden="true">#</a> 暴露服务</h3><ol><li>使用内网穿透工具进行端口映射</li></ol>`,22),d={href:"https://github.com/ehang-io/nps",target:"_blank",rel:"noopener noreferrer"},v=e(`<p><img src="https://minio.kevin2li.top/image-bed/blog/20230521161528.png" alt=""></p><ol start="2"><li>nginx反向代理</li></ol><p>我的公网机器映射端口为8072，访问域名为<code>code-cloud.kevin2li.top</code>。</p><p>nginx默认配置文件路径：<code>/etc/nginx/nginx.conf</code></p><p>nginx参考配置如下：</p><div class="language-nginx line-numbers-mode" data-ext="nginx"><pre class="language-nginx"><code><span class="token comment"># code-cloud</span>
<span class="token directive"><span class="token keyword">server</span></span> <span class="token punctuation">{</span>
	<span class="token directive"><span class="token keyword">server_name</span> code-cloud.kevin2li.top</span><span class="token punctuation">;</span>
	<span class="token directive"><span class="token keyword">listen</span> <span class="token number">443</span> ssl http2</span><span class="token punctuation">;</span>
	<span class="token directive"><span class="token keyword">ssl_certificate</span> /etc/nginx/ssl/kevin2li.top/fullchain.cer</span><span class="token punctuation">;</span>
	<span class="token directive"><span class="token keyword">ssl_certificate_key</span> /etc/nginx/ssl/kevin2li.top/kevin2li.top.key</span><span class="token punctuation">;</span>
	<span class="token directive"><span class="token keyword">ssl_protocols</span> TLSv1 TLSv1.1 TLSv1.2 TLSv1.3</span><span class="token punctuation">;</span>
	
	<span class="token comment"># listen 80 default;</span>
	<span class="token directive"><span class="token keyword">listen</span> <span class="token number">80</span></span><span class="token punctuation">;</span>
	<span class="token directive"><span class="token keyword">if</span> (<span class="token variable">$scheme</span> = http)</span> <span class="token punctuation">{</span>
		<span class="token directive"><span class="token keyword">return</span> <span class="token number">301</span> https://<span class="token variable">$host</span>:443<span class="token variable">$request_uri</span></span><span class="token punctuation">;</span>
	<span class="token punctuation">}</span>

	<span class="token directive"><span class="token keyword">location</span> /</span> <span class="token punctuation">{</span>
		<span class="token directive"><span class="token keyword">proxy_pass</span> http://127.0.0.1:8073</span><span class="token punctuation">;</span>
		<span class="token directive"><span class="token keyword">proxy_set_header</span> Host <span class="token variable">$host</span></span><span class="token punctuation">;</span>
		<span class="token directive"><span class="token keyword">proxy_set_header</span> X-Real-IP <span class="token variable">$remote_addr</span></span><span class="token punctuation">;</span>
		<span class="token directive"><span class="token keyword">proxy_set_header</span> X-Forwarded-For <span class="token variable">$proxy_add_x_forwarded_for</span></span><span class="token punctuation">;</span>
		<span class="token directive"><span class="token keyword">proxy_set_header</span> X-Forwarded-Host <span class="token variable">$http_host</span></span><span class="token punctuation">;</span>
		<span class="token directive"><span class="token keyword">proxy_set_header</span> X-Forwarded-Port <span class="token variable">$server_port</span></span><span class="token punctuation">;</span>
		<span class="token directive"><span class="token keyword">proxy_set_header</span> X-Forwarded-Proto <span class="token variable">$scheme</span></span><span class="token punctuation">;</span>
		<span class="token directive"><span class="token keyword">proxy_set_header</span> Upgrade <span class="token variable">$http_upgrade</span></span><span class="token punctuation">;</span>
		<span class="token directive"><span class="token keyword">proxy_set_header</span> Connection upgrade</span><span class="token punctuation">;</span>
		<span class="token directive"><span class="token keyword">proxy_set_header</span> Accept-Encoding gzip</span><span class="token punctuation">;</span>
		<span class="token directive"><span class="token keyword">proxy_redirect</span> http:// https://</span><span class="token punctuation">;</span>
	<span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>修改完后，测试并启用：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 测试配置文件</span>
<span class="token function">sudo</span> nginx <span class="token parameter variable">-t</span>

<span class="token comment"># 重新加载配置文件</span>
<span class="token function">sudo</span> nginx <span class="token parameter variable">-s</span> reload
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>之后就可以通过你自定义的域名访问了。</p>`,9);function u(k,m){const a=i("ExternalLinkIcon");return p(),o("div",null,[r,n("p",null,[s("如使用"),n("a",d,[s("nps"),l(a)]),s("将本地的8080端口映射到公网机器的8073端口。")]),v])}const h=t(c,[["render",u],["__file","code-server安装与使用教程.html.vue"]]);export{h as default};
